#include <stdio.h>
#include <stdlib.h>

int* calculateStockSpan(int *prices, int n) {
    static int span[200000];
    int *stackPrice = (int*)malloc(n * sizeof(int));
    int *stackSpan = (int*)malloc(n * sizeof(int));
    int top = -1;
    for (int i = 0; i < n; ++i) {
        int cur = 1;
        while (top >= 0 && stackPrice[top] <= prices[i]) {
            cur += stackSpan[top];
            --top;
        }
        stackPrice[++top] = prices[i];
        stackSpan[top] = cur;
        span[i] = cur;
    }
    free(stackPrice);
    free(stackSpan);
    return span;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *prices = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &prices[i]);
        int *ans = calculateStockSpan(prices, N);
        for (int i = 0; i < N; ++i) {
            printf("%d", ans[i]);
            if (i + 1 < N) printf(" ");
        }
        printf("\n");
        free(prices);
    }
    return 0;
}

