#include <bits/stdc++.h>
using namespace std;

vector<int> calculateStockSpan(const vector<int>& prices) {
    vector<int> span;
    span.reserve(prices.size());
    stack<pair<int,int>> st; // {price, span}
    for (int price : prices) {
        int cur = 1;
        while (!st.empty() && st.top().first <= price) {
            cur += st.top().second;
            st.pop();
        }
        st.push({price, cur});
        span.push_back(cur);
    }
    return span;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while (T--) {
        int N; cin>>N;
        vector<int> prices(N);
        for (int i=0;i<N;++i) cin>>prices[i];
        vector<int> ans = calculateStockSpan(prices);
        for (int i=0;i<N;++i) {
            if (i) cout << ' ';
            cout << ans[i];
        }
        cout << '\n';
    }
    return 0;
}

