import java.io.*;
import java.util.*;

public class Main {
    private static int[] calculateStockSpan(int[] prices) {
        int n = prices.length;
        int[] span = new int[n];
        Deque<int[]> stack = new ArrayDeque<>(); // each element: [price, span]
        for (int i = 0; i < n; i++) {
            int cur = 1;
            while (!stack.isEmpty() && stack.peekLast()[0] <= prices[i]) {
                cur += stack.pollLast()[1];
            }
            stack.addLast(new int[]{prices[i], cur});
            span[i] = cur;
        }
        return span;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            st = new StringTokenizer(br.readLine());
            int[] prices = new int[N];
            for (int i = 0; i < N; i++) {
                prices[i] = Integer.parseInt(st.nextToken());
            }
            int[] ans = calculateStockSpan(prices);
            for (int i = 0; i < N; i++) {
                if (i > 0) out.append(' ');
                out.append(ans[i]);
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
}

